135	const PaginatedClusterTable: React.FC<PaginatedClusterTableProps> = ({
136	  selectedClusters,
137	  clusters,
138	  isLoaded,
139	  error,
140	  onChange,
141	}) => {
142	  const { t } = useCustomTranslation();
143	  const [page, setPage] = React.useState(INITIAL_PAGE_NUMBER);
144	  const [perPage, setPerPage] = React.useState(COUNT_PER_PAGE_NUMBER);
145	  const [data, filteredData, onFilterChange] = useListPageFilter(clusters);
146	  const paginatedData: ManagedClusterInfoType[] = React.useMemo(() => {
147	    const [start, end] = getPageRange(page, perPage);
148	    return filteredData.slice(start, end) || [];
149	  }, [filteredData, page, perPage]);
150	
151	  const handleSelectionChange = React.useCallback(
152	    (newSelectedClusters: ManagedClusterInfoType[]) => {
153	      // Merge selections: keep existing selections not in current paginated view,
154	      // and add new selections from current view
155	      const paginatedDataIds = new Set(paginatedData.map((c) => getName(c)));
156	      const preservedSelections = selectedClusters.filter(
157	        (cluster) => !paginatedDataIds.has(getName(cluster))
158	      );
159	      onChange([...preservedSelections, ...newSelectedClusters]);
160	    },
161	    [onChange, selectedClusters, paginatedData]
162	  );
163	
164	  const visibleSelectedClusters = React.useMemo(() => {
165	    const paginatedDataIds = new Set(paginatedData.map((c) => getName(c)));
166	    return selectedClusters.filter((cluster) =>
167	      paginatedDataIds.has(getName(cluster))
168	    );
169	  }, [selectedClusters, paginatedData]);
170	
171	  return (
172	    <>
173	      <Grid>
174	        <GridItem md={8} sm={12} className="pf-v6-u-mt-md">
175	          <ListPageFilter
176	            data={data}
177	            loaded={isLoaded}
178	            onFilterChange={onFilterChange}
179	            hideColumnManagement={true}
180	          />
181	        </GridItem>
182	        <GridItem md={4} sm={12}>
183	          <Pagination
184	            className="pf-v6-u-mt-md"
185	            itemCount={filteredData.length || 0}
186	            widgetId="paginated-list-page"
187	            perPage={perPage}
188	            page={page}
189	            variant={PaginationVariant.bottom}
190	            dropDirection="up"
191	            isStatic
192	            isCompact
193	            onSetPage={(_event, newPage) => setPage(newPage)}
194	            onPerPageSelect={(_event, newPerPage, newPage) => {
195	              setPerPage(newPerPage);
196	              setPage(newPage);
197	            }}
198	          />
199	        </GridItem>
200	      </Grid>
201	      <SelectableTable<ManagedClusterInfoType>
202	        columns={getColumns(t)}
203	        rows={paginatedData}
204	        RowComponent={ClusterRow}
205	        selectedRows={visibleSelectedClusters}
206	        setSelectedRows={handleSelectionChange}
207	        loaded={isLoaded}
208	        loadError={error}
209	        variant={TableVariant.DEFAULT}
210	        isColumnSelectableHidden
211	        isRowSelectable={(cluster) =>
212	          isRowSelectable(cluster, selectedClusters)
213	        }
214	      />
215	    </>
216	  );
217	};
