219	export const SelectClusterList: React.FC<SelectClusterListProps> = ({
220	  selectedClusters,
221	  requiredODFVersion,
222	  dispatch,
223	}) => {
224	  const [managedClusters, loaded, loadError] = useK8sWatchResource<
225	    ACMManagedClusterKind[]
226	  >(getManagedClusterResourceObj());
227	
228	  const [mcvs, mcvsLoaded, mcvsLoadError] = useK8sWatchResource<
229	    ACMManagedClusterViewKind[]
230	  >({
231	    kind: referenceForModel(ACMManagedClusterViewModel),
232	    selector: {
233	      // https://github.com/red-hat-storage/odf-multicluster-orchestrator/blob/release-4.17/controllers/utils/managedclusterview.go#L43
234	      matchLabels: { [MCO_CREATED_BY_LABEL_KEY]: MCO_CREATED_BY_MC_CONTROLLER },
235	    },
236	    isList: true,
237	  });
238	
239	  /*  const clusterNames = useDeepCompareMemoize(
240	    managedClusters.map((c) => getName(c)),
241	    true
242	  );
243	
244	  const {
245	    providersByCluster,
246	    loaded: providersLoaded,
247	    error,
248	  } = useStorageProvisioners(clusterNames); */
249	
250	  const allLoaded = loaded && mcvsLoaded; // && providersLoaded;
251	  const anyError = loadError || mcvsLoadError; // || error;
252	
253	  const clusters: ManagedClusterInfoType[] = React.useMemo(() => {
254	    if (!!requiredODFVersion && allLoaded && !anyError)
255	      // TODO: Switch from using the MCV-based odf-info ConfigMap to using
256	      // the odf-client-info ConfigMap from the openshift-operators namespace
257	      return getManagedClusterInfoTypes(
258	        managedClusters,
259	        mcvs,
260	        requiredODFVersion
261	        //  providersByCluster
262	      );
263	
264	    return [];
265	  }, [
266	    requiredODFVersion,
267	    managedClusters,
268	    mcvs,
269	    allLoaded,
270	    anyError,
271	    // providersByCluster,
272	  ]);
273	
274	  const onChange = (selectedClusterList: ManagedClusterInfoType[]) => {
275	    dispatch({
276	      type: DRPolicyActionType.SET_SELECTED_CLUSTERS,
277	      payload: selectedClusterList,
278	    });
279	
280	    /*   if (selectedClusterList?.length >= 2) {
281	      const doClustersHaveODF = selectedClusterList?.every(
282	        (cluster) => cluster?.odfInfo?.isValidODFVersion
283	      );
284	      dispatch({
285	        type: DRPolicyActionType.SET_DO_CLUSTERS_HAVE_ODF,
286	        payload: doClustersHaveODF,
287	      });
288	
289	      dispatch({
290	        type: DRPolicyActionType.SET_REPLICATION_BACKEND,
291	        payload: doClustersHaveODF
292	          ? BackendType.DataFoundation
293	          : BackendType.ThirdParty,
294	      });
295	    } */
296	    if (selectedClusterList.length < 2) {
297	      dispatch({
298	        type: DRPolicyActionType.SET_CLUSTER_SELECTION_VALIDATION,
299	        payload: false,
300	      });
301	
302	      /*   dispatch({
303	        type: DRPolicyActionType.SET_DO_CLUSTERS_HAVE_ODF,
304	        payload: false,
305	      }); */
306	    }
307	  };
308	
309	  const clustersLoaded = allLoaded && !!requiredODFVersion;
310	
311	  return (
312	    <PaginatedClusterTable
313	      selectedClusters={selectedClusters}
314	      clusters={clusters}
315	      isLoaded={clustersLoaded}
316	      error={loadError}
317	      onChange={onChange}
318	    />
319	  );
320	};
321	
322	type SelectClusterListProps = {
323	  selectedClusters: ManagedClusterInfoType[];
324	  requiredODFVersion: string;
325	  dispatch: React.Dispatch<DRPolicyAction>;
326	};
327	
328	type PaginatedClusterTableProps = {
329	  selectedClusters: ManagedClusterInfoType[];
330	  clusters: ManagedClusterInfoType[];
331	  isLoaded: boolean;
332	  error: any;
333	  onChange: (selectedClusterList: ManagedClusterInfoType[]) => void;
334	};

